"""Обработчик секции markdown конфигурации проекта: logic (none / llm_processing), LLM-настройки."""from __future__ import annotationsfrom types import SimpleNamespacefrom typing import Any# logic: none — сохранять как есть; llm_processing — обрабатывать LLMMARKDOWN_LOGICS = SimpleNamespace(    none="none",    llm_processing="llm_processing",    options=(        ("none", "Сохранять как есть"),        ("llm_processing", "Обрабатывать LLM"),    ),    valid_codes=frozenset({"none", "llm_processing"}),)# Тексты экрана настроек проекта (вкладка «Создание разметки») — единый источник для GUIMARKDOWN_MODE_DESCRIPTIONS: dict[str, str] = {    MARKDOWN_LOGICS.none: "Текст сохраняется без изменений.",    MARKDOWN_LOGICS.llm_processing: (        "Текст передаётся в LLM для форматирования в Markdown (параметры модели ниже)."    ),}MARKDOWN_SETTINGS_UI = SimpleNamespace(    help_sidebar_title="Пояснения",    mode_field_label="Режим создания",    llm_pick_model_header="Выбор модели",    llm_tune_model_header="Настройка модели",    llm_provider_hint="Провайдер LLM для обработки текста в Markdown",    llm_model_hint="Модель для чат-запросов (форматирование текста)",    llm_reasoning_hint="Выделение токенов на размышления модели",    llm_temperature_hint="Случайность ответа (0.0 — детерминированный вывод)",    system_prompt_label="Системный промпт",    system_prompt_hint=(        "В системный промпт будут добавлены инструкции для создания разметки, "        "если требуется вы можете уточнить поведение модели."    ),)MARKDOWN_HELP_ARTICLE = """Раздел «Создание разметки» задаёт, как из сырого текста (после извлечения и опциональной обработки изображений) получается итоговый Markdown.Режимы:- Сохранять как есть — текст не меняется, только сохраняется в .md файлы.- Обрабатывать LLM — фрагменты текста отправляются в выбранную чат-модель с системным промптом; модель возвращает отформатированный Markdown (заголовки, списки, таблицы и т.д.).Доступность провайдеров и моделей зависит от добавленных API-ключей. Добавить ключ можно в настройках приложения на главном экране.Список доступных чат-моделей настраивается в «Настройка моделей» на главном экране. Для этапа разметки подходят любые текстовые чат-модели (поддержка изображений не требуется).""".strip()MARKDOWN_DEFAULTS = SimpleNamespace(    llm_provider="",    llm_model="",    llm_reasoning="low",    llm_temperature=0.5,    llm_system_prompt="",)MARKDOWN_KEYS = SimpleNamespace(    markdown_logic="markdown_logic",    llm_provider="llm_provider",    llm_model="llm_model",    llm_reasoning="llm_reasoning",    llm_temperature="llm_temperature",    llm_system_prompt="llm_system_prompt",)class MarkdownConfig:    """Статический класс для работы с секцией markdown: умолчания и валидация."""    MARKDOWN_LOGICS = MARKDOWN_LOGICS    MARKDOWN_MODE_DESCRIPTIONS = MARKDOWN_MODE_DESCRIPTIONS    MARKDOWN_SETTINGS_UI = MARKDOWN_SETTINGS_UI    MARKDOWN_HELP_ARTICLE = MARKDOWN_HELP_ARTICLE    MARKDOWN_DEFAULTS = MARKDOWN_DEFAULTS    MARKDOWN_KEYS = MARKDOWN_KEYS    @staticmethod    def get_default() -> dict[str, Any]:        """Возвращает словарь умолчаний для секции markdown."""        L = MARKDOWN_LOGICS        D = MARKDOWN_DEFAULTS        K = MARKDOWN_KEYS        return {            K.markdown_logic: L.none,            K.llm_provider: D.llm_provider,            K.llm_model: D.llm_model,            K.llm_reasoning: D.llm_reasoning,            K.llm_temperature: D.llm_temperature,            K.llm_system_prompt: D.llm_system_prompt,        }    @staticmethod    def validate(data: Any) -> list[str]:        """Проверяет данные секции markdown. Возвращает список сообщений об ошибках (пустой — данные валидны)."""        errors: list[str] = []        if not isinstance(data, dict):            errors.append("Markdown: ожидается объект (dict).")            return errors        L = MARKDOWN_LOGICS        K = MARKDOWN_KEYS        logic = data.get(K.markdown_logic) or L.none        if isinstance(logic, str):            logic = logic.strip().lower()        else:            logic = ""        if logic not in L.valid_codes:            errors.append(                f"Markdown: markdown_logic должен быть один из: {', '.join(sorted(L.valid_codes))}."            )        for key in (            K.llm_provider,            K.llm_model,            K.llm_reasoning,            K.llm_system_prompt,        ):            val = data.get(key)            if val is not None and not isinstance(val, str):                errors.append(f"Markdown: поле {key} должно быть строкой.")        t = data.get(K.llm_temperature)        if t is not None:            try:                tf = float(t)                if not (0.0 <= tf <= 2.0):                    errors.append("Markdown: llm_temperature должен быть от 0.0 до 2.0.")            except (TypeError, ValueError):                errors.append("Markdown: llm_temperature должен быть числом.")        reason = (data.get(K.llm_reasoning) or "").strip().lower()        if reason and reason not in ("disabled", "low", "medium", "high"):            errors.append(                "Markdown: llm_reasoning должен быть один из: disabled, low, medium, high."            )        return errors